window.__QUIZ_DATA__=[{"id":"objective>Physics>1995>1","subject":"Physics","year":"1995","type":"Objective","topic":"FUNDAMENTAL AND DERIVED QUANTITIES AND UNITS : FUNDAMENTAL QUANTITIES AND UNITS","question":"Which of the following is a fundamental quantity?","images":[],"options":{"A":"Heat capacity","B":"Electric current","C":"Torque","D":"Reactance"},"answer":"B","explanation":"Fundamental quantities are independent quantities examples are mass, length, time, temperature, current, amount of substance, luminous intensity","marks":"1","difficulty":"1"},{"id":"objective>Physics>1995>2","subject":"Physics","year":"1995","type":"Objective","topic":"SPEED AND VELOCITY : CONCEPT OF SPEED","question":"A boy cycles continuously through a distance of 1.0 km in 5 minutes. Calculate his average speed.","images":[],"options":{"A":"0.3 ms-1","B":"3.3 ms-1","C":"16.6 ms-1","D":"20.0 ms-1"},"answer":"B","explanation":"Averagespeed=Total distanceTotal time=1 x 1000 m5 x 60 s=3.33 ms-1","marks":"1","difficulty":"1"},{"id":"objective>Physics>1995>3","subject":"Physics","year":"1995","type":"Objective","topic":"TIME : MEASUREMENT OF TIME","question":"A student found out from a simple pendulum experiment that 20 oscillations were completed in 38 seconds. What is the period of oscillation of the pendulum.","images":[],"options":{"A":"8.0 s","B":"3.8 s","C":"2.0 s","D":"1.9 s"},"answer":"D","explanation":"The period of oscillation is the time taken for one complete cycle of oscillation. In this case, 20 oscillations were completed in 38 seconds. Therefore, the period of oscillation is 38 s / 20 = 1.9 s.","marks":"1","difficulty":"1"},{"id":"objective>Physics>1995>4","subject":"Physics","year":"1995","type":"Objective","topic":"WORK, ENERGY AND POWER : WORK DONE IN A GRAVITATIONAL FIELD","question":"A body of mass 7.5 kg is to be pulled up along a plane which is inclined at 30o to the horizontal. If the efficiency of the plane is 75%, what is the minimum force required to pull the body up the plane?","images":[],"options":{"A":"5.0 N","B":"20.0 N","C":"50.0 N","D":"75.0 N"},"answer":"C","explanation":"m=7.5kg;\u03b8=30o;\u03b5=75%  L=mg=7.5x10=75N  V.R=1sin \u03b8=10.5=2  \u03b5=LEx1V.Rx100%==>75%=75Ex12x100%  =75=752Ex100  =75100=752E  =150=1E  \u2234E=50.0N","marks":"1","difficulty":"3"},{"id":"objective>Physics>1995>5","subject":"Physics","year":"1995","type":"Objective","topic":"MOTION : SIMPLE IDEAS OF CIRCULAR MOTION","question":"The angular speed of an object describing a circle of radius 4m with linear constant speed of 10 ms-1 is","images":[],"options":{"A":"40.00 rads-1","B":"14.00 rads-1","C":"2.50 rads-1","D":"1.58 rads-1"},"answer":"C","explanation":"r=4m;v=10ms-1;\u03c9=?;v=\u03c9r;\u03c9=vr=104=2.50rads-1","marks":"1","difficulty":"2"},{"id":"objective>Physics>1995>6","subject":"Physics","year":"1995","type":"Objective","topic":"PROJECTILE MOTION :","question":"At what angle to the horizontal must the nozzle of a machine gun be kept when firing to obtain a maximum horizontal range for the bullets?","images":[],"options":{"A":"0.0o","B":"22.5o","C":"30.0o","D":"45.0o"},"answer":"D","explanation":"R=u2sin 2\u03b8g  Rmax=u2sin 2(45)g=u2sin 90g=u2g(sincesin90o=1)","marks":"1","difficulty":"2"},{"id":"objective>Physics>1995>7","subject":"Physics","year":"1995","type":"Objective","topic":"SIMPLE HARMONIC MOTION : PERIOD, FREQUENCY AND AMPLITUDE OF A BODY EXECUTING S.H.M","question":"Which of the following will reduce the frequency of oscillation of a simple pendulum?","images":[],"options":{"A":"Increasing the mass of the bob","B":"Decreasing the mass of the bob","C":"Increasing the length of the string","D":"Decreasing the length of the string"},"answer":"C","explanation":"The frequency of oscillation of a simple pendulum is given by the formula f = 1/2\u03c0 \u221a(g/l), where g is the acceleration due to gravity and l is the length of the pendulum. From this formula, it can be seen that the frequency is inversely proportional to the square root of the length of the pendulum. Therefore, increasing the length of the pendulum will reduce the frequency of oscillation. The mass of the bob does not affect the frequency.","marks":"1","difficulty":"1"},{"id":"objective>Physics>1995>8","subject":"Physics","year":"1995","type":"Objective","topic":"SPEED AND VELOCITY : CONCEPT OF SPEED","question":"A car travelling at a uniform speed of 120 kmhr-1 passes two stations in 4 minutes. Calculate the distance between the two stations.","images":[],"options":{"A":"8 km","B":"15 km","C":"22 km","D":"30 km"},"answer":"A","explanation":"The distance covered by a moving object is given by the formula d = vt, where v is the speed and t is the time. In this case, the speed of the car is 120 km/hr and the time is 4 minutes, which is equivalent to 4/60 = 0.067 hours. Substituting these values into the formula gives d = 120 * 0.067 = 8 km.","marks":"1","difficulty":"1"},{"id":"objective>Physics>1995>9","subject":"Physics","year":"1995","type":"Objective","topic":"MACHINES :","question":"A machine has an efficiency of 60%. If the machine is required to overcome a load of 30 N with a force of 20 N. Calculate its mechanical advantage?","images":[],"options":{"A":"0.7","B":"0.9","C":"1.5","D":"2.5"},"answer":"C","explanation":"\u03b5=60%;L=30N;E=20N;M.A=?  M.A=LE=3020=1.5","marks":"1","difficulty":"2"},{"id":"objective>Physics>1995>10","subject":"Physics","year":"1995","type":"Objective","topic":"FLUID AT REST : EQUILIBRIUM OF BODIES: ARCHIMEDES\u2019 PRINCIPLE","question":"A body weighing 10 N in air is partially immersed in water. It displaces water of mass 0.3 kg. What is the upthrust on the body? (g = 10 ms-2)","images":[],"options":{"A":"13.0 N","B":"7.0 N","C":"3.3 N","D":"3.0 N"},"answer":"D","explanation":"Upthrust = Weight of fluid displaced = 0.3 x 10 = 3.0 N","marks":"1","difficulty":"2"},{"id":"objective>Physics>1995>11","subject":"Physics","year":"1995","type":"Objective","topic":"HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT","question":"A mercury-in-glass thermometer reads -20o at the ice point and 100o at the steam point. Calculate the Celsius temperature corresponding to 70o on the thermometer.","images":[],"options":{"A":"41.0oC","B":"50.0oC","C":"62.5oC","D":"75.0oC"},"answer":"D","explanation":"\u223470 - (-20)100 - (-20)=x - 0100 - 0  90120=x100  x=90 x 100120=75.0oC","marks":"1","difficulty":"2"},{"id":"objective>Physics>1995>12","subject":"Physics","year":"1995","type":"Objective","topic":"HEAT ENERGY : THERMAL EXPANSION","question":"A brass rod is 2 m long at a certain temperature. Calculate the linear expansion of the rod for a temperature change of 100 K. (Take linear expansivity of brass as 1.8 x 10-5 K-1)","images":[],"options":{"A":"0.3600 m","B":"0.1800 m","C":"0.360 m","D":"0.0036 m"},"answer":"D","explanation":"L=2m;\u03b1=1.8x10-5 K-1;\u2206\u03b8=100K  \u03b1=\u2206LL\u2206\u03b8  \u2206L=\u03b1L\u2206\u03b8  \u2206L=1.8x10-5x2x100=3.6x10-3  \u2234\u2206L=0.0036m","marks":"1","difficulty":"2"},{"id":"objective>Physics>1995>13","subject":"Physics","year":"1995","type":"Objective","topic":"WORK, ENERGY AND POWER : CONSERVATION OF MECHANICAL ENERGY","question":"A body of specific heat capacity 450 Jkg-1K-1 falls to the ground from rest through a vertical height of 20 m. Assuming conservation of energy, calculate the change in temperature of the body striking the ground level. (g = 10 ms-2)","images":[],"options":{"A":"0oC","B":"29oC","C":"49oC","D":"94oC"},"answer":"C","explanation":"c=450Jkg-1K-1;h=20m;\u03b8=?;g=10ms-2  Heatenergy=Potentialenergy  mc\u2206\u03b8=mgh  c\u2206\u03b8=gh  \u2234\u2206\u03b8=ghc=10x20450=2045=49oC","marks":"1","difficulty":"3"},{"id":"objective>Physics>1995>14","subject":"Physics","year":"1995","type":"Objective","topic":"HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT","question":"Hot water at temperature of t is added to twice that amount of water at a temperature of 30oC. If the resulting temperature of the mixture is 50oC, calculate t","images":[],"options":{"A":"90oC","B":"80oC","C":"50oC","D":"40oC"},"answer":"A","explanation":"Heat loss by hot water = Heat gained by water  mc(t - 50) = 2mc(50 - 30)  t - 50 = 2(20)  t - 50 = 40  t = 40 + 50  t = 90oC","marks":"1","difficulty":"2"},{"id":"objective>Physics>1995>15","subject":"Physics","year":"1995","type":"Objective","topic":"FLUID AT REST : PRESSURE IN FLUIDS","question":"An air bubble of volume 2 cm3 is formed 20 m under water. What will be its volume when it rises to just below the surface of the water if the atmospheric pressure is equivalent to a height of 10 m of water?","images":[],"options":{"A":"6 cm3","B":"4 cm3","C":"3 cm3","D":"2 cm3"},"answer":"A","explanation":"P1 = 20 m + 10 m = 30 m = 3000 cm  V1 = 2 cm3  P2 = 10 m = 1000 cm  V2 = ?  P1V1 = P2V2  3000 x 2 = 1000 x  V2  \u2234 V2 = 6 cm3","marks":"1","difficulty":"3"},{"id":"objective>Physics>1995>16","subject":"Physics","year":"1995","type":"Objective","topic":"FLUID AT REST : PRESSURE IN FLUIDS","question":"The pressure of a given mass of gas changes from 200 Nm-2 to 100 Nm-2, while its temperature drops from 127oC to  -73oC. Calculate the ratio of the final volume of the gas to its initial volume.","images":[],"options":{"A":"2.4 : 1","B":"2.0 : 1","C":"1.2 : 1","D":"1.0 : 1"},"answer":"D","explanation":"P1=200Nm-2;P2=100Nm-2;T1=127+273=400K;T2=-73+273=200K;V2V1=?  P1V1T1=P2V2T2  P1V1T2=P2V2T1  V2V1=P1T2P2T1=200 x 200100 x 400=11  \u2234 V2 : V1 = 1.0 : 1","marks":"1","difficulty":"3"},{"id":"objective>Physics>1995>17","subject":"Physics","year":"1995","type":"Objective","topic":"HEAT ENERGY : THERMAL EXPANSION","question":"The temperature of glass vessel containing 100 cm3 of mercury is raised from 10oC to 100oC. Calculate the apparent cubic expansion of the mercury. (Real cubic expansivity of mercury = 1.8 x 10-4 K-1, Cubic expansivity of glass = 2.4 x 10-5 K-1)","images":[],"options":{"A":"0.52 cm3","B":"1.42 cm3","C":"1.87 cm3","D":"14.22 cm3"},"answer":"B","explanation":"\u03b3=V2 - V1V1(\u03b82 - \u03b81) ==> V2 = V1(1 + \u03b3(\u03b82 - \u03b81))  (i) For mercury  V1 = 100 cm3  \u03b81 = 10oC  \u03b82 = 100oC  \u03b3r = 1.8 x 10-4 K-1  V2 = ?  V2 = 100(1 + 1.8 x 10-4 x (100 - 10)) = 100(1 + 1.8 x 10-4 x 90)  = 100(1 + 0.0162) = 100(1.0162)  V2 = 101.62 cm3    (ii) For glass  V1 = 100 cm3  \u03b81 = 10oC  \u03b82 = 100oC  \u03b3 = 2.4 x 10-5 K-1  V2 = ?  V2 = 100(1 + 2.4 x 10-5 x (100 - 10)) = 100(1 + 2.4 x 10-5 x 90)  = 100(1 + 0.00216) = 100(1.00216)  V2 = 100.216 cm3    Finally,  Volume of mercury expelled = 101.62 - 100.216 = 1.404 cm3  Volume of mercury remaining = 100.216 cm3  Temperature rise = 100oC - 10oC = 90oC  Apparent cubic expansion of the mercury \u03b3a   =Volume of mercury expelledVolume of mercury remaining x temp. rise=1.404100.216 x 90=1.4049019.44  \u2234  \u03b3a  = 1.56 x 10-4 K-1    Since the options are in volume (cm3), the answer is B which is the volume of mercury expelled","marks":"1","difficulty":"3"},{"id":"objective>Physics>1995>18","subject":"Physics","year":"1995","type":"Objective","topic":"HEAT ENERGY : SPECIFIC HEAT CAPACITY","question":"An iron rod of mass 2 kg and at a temperature of 280oC is dropped into some quantity of water initially at a temperature of 30oC. If the temperature of the mixture is 70oC, calculate the mass of the water. (Neglect heat losses to the sorroundings)  [Specific heat capacity of iron = 460 Jkg-1K-1]  [Specific heat capacity of water = 4200 Jkg-1K-1]","images":[],"options":{"A":"0.58 kg","B":"0.77 kg","C":"1.15 kg","D":"1.50 kg"},"answer":"C","explanation":"ms = 2 kg; cs = 460 Jkg-1K-1; mw = ?; cw = 4200 Jkg-1K-1; \u03b81 = 280oC; \u03b82 = 30oC; \u03b83 = 70oC  Heat loss = Heat gained  mscs(\u03b81 - \u03b83) = mwcw(\u03b83 - \u03b82)  2 x 460 x (280 - 70) = mw x 4200 x (70 - 30)  2 x 460 x 210 = mw x 4200 x 40  193,200 = 168,000mw  \u2234mw=193200168000=1.15kg","marks":"1","difficulty":"3"},{"id":"objective>Physics>1995>19","subject":"Physics","year":"1995","type":"Objective","topic":"HEAT ENERGY : SPECIFIC LATENT HEAT OF FUSION","question":"How much heat is required to covert 20 g of ice at 0oC to water at the same temperature?  [Specific latent heat of ice = 336 Jg-1]","images":[],"options":{"A":"1.35 x 103 J","B":"5.38 x 103 J","C":"6.72 x 103 J","D":"7.06 x 103 J"},"answer":"C","explanation":"The heat required to convert ice at 0oC to water at the same temperature is given by the formula: Q = m * L, where m is the mass of the ice and L is the specific latent heat of ice. Substituting the given values, we get Q = 20 g * 336 Jg-1 = 6.72 x 103 J. Therefore, the correct option is 3.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1995>20","subject":"Physics","year":"1995","type":"Objective","topic":"HEAT ENERGY : SPECIFIC HEAT CAPACITY","question":"When two objects P and Q are supplied with the same quantity of heat, the temperature change in P is observed to be twice that in Q.  If the masses of P and Q are the same, calculate the ratio of the specific heat capacities of Q to P.","images":[],"options":{"A":"4 : 1","B":"2 : 1","C":"1 : 1","D":"1 : 2"},"answer":"B","explanation":"\u2206\u03b8P = 2 x \u2206\u03b8Q  mP = mQ  cQ : cP = ?  HP = HQ (given)  i.e mP x cP x \u2206\u03b8P = mQ x cQ x \u2206\u03b8Q  Since \u2206\u03b8P = 2 x \u2206\u03b8Q and mP = mQ  \u2234 mQ x cP x 2 x \u2206\u03b8Q = mQ x cQ x \u2206\u03b8Q  cP x 2 = cQ  cQcP=21\u2234cQ:cP=2:1","marks":"1","difficulty":"2"},{"id":"objective>Physics>1995>21","subject":"Physics","year":"1995","type":"Objective","topic":"LIGHT WAVES : REFLECTION OF LIGHT AT CURVED SURFACES","question":"A ray of light is incident on mirror m1 and after reflection is incident on mirror m2 as shown in the diagram below. Calculate the angle of reflection of the ray at mirror m2.","images":["data:image/png;base64,"],"options":{"A":"120o","B":"90o","C":"60o","D":"30o"},"answer":"D","explanation":"i at m1 = 60o \u21d2 r = 60o  at m1 (law of reflection io = ro)  i at m2 = 30o  i = r, \u2234 r = 30o","marks":"1","difficulty":"3"},{"id":"objective>Physics>1995>22","subject":"Physics","year":"1995","type":"Objective","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES","question":"A ray of light is incident on a body x as shown in the diagram below. What is the refractive index of the body?","images":["data:image/png;base64,"],"options":{"A":"1.63","B":"1.50","C":"1.49","D":"1.33"},"answer":"A","explanation":"\u03bb=sin isin r=sin 60osin 32o=1.63","marks":"1","difficulty":"2"},{"id":"objective>Physics>1995>23","subject":"Physics","year":"1995","type":"Objective","topic":"LIGHT WAVES : RECTILINEAR PROPAGATION OF LIGHT","question":"Light travels in straight lines. In which of the following is this principle manifested?  I. Pinhole camera  II. Formation of shadows  III. Diffraction of light  IV. Occurrence of eclipse","images":[],"options":{"A":"I and III only","B":"II and III only","C":"I, II and III only","D":"I, II and IV only"},"answer":"D","explanation":"Pinhole camera, shadow formation and the occurence of eclipse are as a result of the rectilinear propagation of light","marks":"1","difficulty":"1"},{"id":"objective>Physics>1995>24","subject":"Physics","year":"1995","type":"Objective","topic":"LIGHT WAVES : SOURCES OF LIGHT","question":"The image of any real object formed by a diverging lens is always","images":[],"options":{"A":"inverted","B":"magnified","C":"erect","D":"real"},"answer":"C","explanation":"For all positions of the object formed by a concave (diverging) lens, the image is virtual, erect and diminished.","marks":"1","difficulty":"1"},{"id":"objective>Physics>1995>25","subject":"Physics","year":"1995","type":"Objective","topic":"LIGHT WAVES : SOURCES OF LIGHT","question":"Which of the following is not self-luminous?","images":[],"options":{"A":"Incadescent electric bulb","B":"Incadescent flourescent tube","C":"Lighted candle","D":"The moon"},"answer":"D","explanation":"The moon is not self-luminous. Self-luminous objects are those that can emit light on their own. The moon does not emit light; it only reflects light from the sun.","marks":"1","difficulty":"1"},{"id":"objective>Physics>1995>26","subject":"Physics","year":"1995","type":"Objective","topic":"LIGHT WAVES : REFLECTION OF LIGHT AT CURVED SURFACES","question":"An object is placed on the principal axis and at the centre of curvature of a concave mirror. The image of the object formed by the mirror is","images":[],"options":{"A":"real, inverted and magnified","B":"at the principal focus","C":"real and diminished","D":"at the centre of curvature"},"answer":"D","explanation":"The image formed when an object is placed at centre of curvature of a concave (converging) mirror is real, inverted, same size as the object and at the centre of curvature of the mirror","marks":"1","difficulty":"2"},{"id":"objective>Physics>1995>27","subject":"Physics","year":"1995","type":"Objective","topic":"PRODUCTION AND PROPAGATION OF WAVES : FREQUENCY (F), WAVELENGTH(\ud835\udecc), PERIOD (T) AND VELOCITY (V)","question":"A wire is stretched between two points, 1 m apart, if the speed of the wave generated on plucking the wire is 200 ms-1, what is the minimum frequency which will resonate with the wire.","images":[],"options":{"A":"50 Hz","B":"75 Hz","C":"100 Hz","D":"200 Hz"},"answer":"D","explanation":"\u03bb=1m;v=200 ms-1;f=?;f=v\u03bb=2001=200Hz","marks":"1","difficulty":"2"},{"id":"objective>Physics>1995>28","subject":"Physics","year":"1995","type":"Objective","topic":"PRODUCTION AND PROPAGATION OF WAVES : SPEED, FREQUENCY AND WAVELENGTH","question":"Sixty complete waves pass a particular point in 4s. If the distance between three successive troughs of the waves is 15 m, calculate the speed of the waves.","images":[],"options":{"A":"300.0 ms-1","B":"225.0 ms-1","C":"112.5 ms-1","D":"75.0 ms-1"},"answer":"B","explanation":"f=no of oscillation madet(s)=604=15Hz  \u03bb=15m;v=15x15=225.0ms-1","marks":"1","difficulty":"2"},{"id":"objective>Physics>1995>29","subject":"Physics","year":"1995","type":"Objective","topic":"SOUND WAVES : TRANSMISSION OF SOUND WAVES","question":"Which of the following media allow(s) the transmission of sound wave through them?  I. Air  II. Liquid  III. Solid","images":[],"options":{"A":"I only","B":"II only","C":"III only","D":"I, II and III only"},"answer":"D","explanation":"Sound waves are mechanical waves, which means they require a medium to travel through. They can travel through all three states of matter: gases (like air), liquids, and solids. Therefore, all three options I, II, and III are correct.","marks":"1","difficulty":"1"},{"id":"objective>Physics>1995>30","subject":"Physics","year":"1995","type":"Objective","topic":"TYPES OF WAVES : TRANSVERSE AND LONGITUDINAL","question":"Which of the following wave characteristic can be used to distinguish a transverse wave from a longitudinal wave?","images":[],"options":{"A":"Reflection","B":"Refraction","C":"Diffraction","D":"Polarisation"},"answer":"D","explanation":"Polarisation only occurs with a wave whose direction is perpendicular to its vibration (i.e transverse waves)","marks":"1","difficulty":"2"},{"id":"objective>Physics>1995>31","subject":"Physics","year":"1995","type":"Objective","topic":"SOUND WAVES : ECHOES AND REVERBERATION","question":"A sound note of frequency 250 Hz and a wavelength 1.3 m is produced at a point near a hill. If the echo of the sound is recieved 1 second later at that point, how far away is the hill from the point?","images":[],"options":{"A":"131.3 m","B":"162.5 m","C":"248.7 m","D":"261.3 m"},"answer":"B","explanation":"f = 250 Hz; \u03bb = 1.3 m; t = 1 s; d = ?  v = f\u03bb = 250 x 1.3 = 325 ms-1  v=2dt \u2234d=vt2=325 x 12=162.5m","marks":"1","difficulty":"3"},{"id":"objective>Physics>1995>32","subject":"Physics","year":"1995","type":"Objective","topic":"PRODUCTION AND PROPAGATION OF WAVES : FREQUENCY (F), WAVELENGTH(\ud835\udecc), PERIOD (T) AND VELOCITY (V)","question":"The period of a wave is 0.02 second. Calculate its wavelength if its speed is 330 ms-1","images":[],"options":{"A":"6.6 m","B":"5.0 m","C":"4.0 m","D":"3.3 m"},"answer":"A","explanation":"T=0.02s;\u03bb=?;v=330ms-1;f=1T=10.02=50Hz  \u03bb=vf=33050=6.6m","marks":"1","difficulty":"1"},{"id":"objective>Physics>1995>33","subject":"Physics","year":"1995","type":"Objective","topic":"SIMPLE A.C. CIRCUITS : PEAK AND R..M.S. VALUES","question":"An alternating voltage with a frequency of 50 Hz has a period of","images":[],"options":{"A":"0.02 s","B":"0.05 s","C":"0.20 s","D":"0.50 s"},"answer":"A","explanation":"The period of a wave is the reciprocal of its frequency. Therefore, period = 1 / frequency. Substituting the given frequency, we get period = 1 / 50 Hz = 0.02 s.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1995>34","subject":"Physics","year":"1995","type":"Objective","topic":"SOUND WAVES : HARMONIES AND OVERTONES","question":"A listener can detect the instrument from which a note is being sounded because different instruments produce the same note with different","images":[],"options":{"A":"Frequencies","B":"Pitches","C":"Loudness","D":"Overtones"},"answer":"D","explanation":"Quality (overtones) is a characteristics note of a musical instrument which distinguishes it from another note of the same pitch and loudness produced by another instrument","marks":"1","difficulty":"1"},{"id":"objective>Physics>1995>35","subject":"Physics","year":"1995","type":"Objective","topic":"GRAVITATIONAL FIELD : GRAVITATIONAL POTENTIAL AND ESCAPE VELOCITY","question":"What is the escape velocity of a body on the surface of the earth of radius R if the gravitational constant is G and the mass of the earth is M? (Neglect energy losses to the sorroundings)","images":[],"options":{"A":"\u221a2GR","B":"\u221a2GR","C":"\u221a2GR2","D":"\u221a2GM"},"answer":"D","explanation":"ve = \u221a2gR  Since gR = GM  Therefore, ve = \u221a2GM","marks":"1","difficulty":"3"},{"id":"objective>Physics>1995>36","subject":"Physics","year":"1995","type":"Objective","topic":"ELECTRIC FIELD : CONCEPTS OF ELECTRIC FIELD, ELECTRIC FIELD INTENSITY (POTENTIAL GRADIENT) AND ELECTRIC POTENTIAL.","question":"A charge of 1.6 x 10-10 C is placed in a uniform electric field of intensity 2.0 x 105 NC-1. What is the magnitude of the electric force exerted on the charge?","images":[],"options":{"A":"3.2 x 105 N","B":"1.8 x 105 N","C":"3.2 x 10-5 N","D":"1.8 x 10-5 N"},"answer":"C","explanation":"The force exerted on a charge in an electric field is given by the formula F = qE, where F is the force, q is the charge, and E is the electric field intensity. In this case, the charge q is 1.6 x 10-10 C and the electric field intensity E is 2.0 x 105 NC-1. Substituting these values into the formula gives F = (1.6 x 10-10 C) * (2.0 x 105 NC-1) = 3.2 x 10-5 N. Therefore, the magnitude of the electric force exerted on the charge is 3.2 x 10-5 N.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1995>37","subject":"Physics","year":"1995","type":"Objective","topic":"HEAT ENERGY : THERMAL EXPANSION","question":"A balloon containing 546 cm3 of air is heated from 0oC to 10oC. If the pressure is kept constant, what will be its volume at 10oC.","images":[],"options":{"A":"526 cm3","B":"546 cm3","C":"556 cm3","D":"566 cm3"},"answer":"D","explanation":"V1T1=V2T2==>  5460 + 273=V210 + 273  V2=546 x 283273=566cm3","marks":"1","difficulty":"2"},{"id":"objective>Physics>1995>38","subject":"Physics","year":"1995","type":"Objective","topic":"SIMPLE A.C. CIRCUITS : INDUCTANCE","question":"Calculate the inductance L of the coil in the circuit shown beside.","images":["data:image/png;base64,"],"options":{"A":"14.4 H","B":"3.8 H","C":"0.6 H","D":"0.4 H"},"answer":"C","explanation":"V=IXL  XL=VI=2402=120\u03a9  XL=2\u03c0fL  120=2\u03c0x100\u03c0xL  120=200L  L=120200=0.6H","marks":"1","difficulty":"3"},{"id":"objective>Physics>1995>39","subject":"Physics","year":"1995","type":"Objective","topic":"SIMPLE A.C. CIRCUITS : VECTOR DIAGRAMS","question":"A series R-L-C circuit is shown in the diagram above. Which of the following vector diagrams correctly represents the phase relationship among I, V, VR, VC and VL if VC is greater than VL and the symbols have their usual meaning?","images":["data:image/png;base64,","data:image/png;base64,","data:image/png;base64,","data:image/png;base64,","data:image/png;base64,"],"options":{"A":"","B":"","C":"","D":""},"answer":"D","explanation":"i.e VL - VC = -ve value (VC - VL = +ve)    Fromtan\u2205=VL - VCR  it shows that VL - VC will be inverted on the y-axis since VC > VL    So, the correct option is D not A","marks":"1","difficulty":"3"},{"id":"objective>Physics>1995>40","subject":"Physics","year":"1995","type":"Objective","topic":"ELECTRIC FIELD : CONCEPTS OF ELECTRIC FIELD, ELECTRIC FIELD INTENSITY (POTENTIAL GRADIENT) AND ELECTRIC POTENTIAL.","question":"Calculate the electric potential at a distance of 20.0 cm from a point charge of 0.015 C placed in air of permittivity  (Take14\u03c0\u03b5oas9.0x109Nm2C-2)","images":[],"options":{"A":"3.40 x 109 V","B":"6.75 x 108 V","C":"6.75 x 106 V","D":"3.40 x 105 V"},"answer":"C","explanation":"The electric potential (V) at a distance (r) from a point charge (q) is given by the formula V = kq/r, where k is Coulomb's constant. Substituting the given values, we get V = (9.0 x 10^9 Nm^2/C^2 * 0.015 C) / 0.20 m = 6.75 x 10^6 V. Therefore, the correct answer is option 3.","marks":"1","difficulty":"3"},{"id":"objective>Physics>1995>41","subject":"Physics","year":"1995","type":"Objective","topic":"SIMPLE A.C. CIRCUITS : REACTANCE AND IMPEDANCE","question":"Calculate the inductive reactance of the circuit shown below","images":["data:image/png;base64,"],"options":{"A":"50.00 \u03a9","B":"5.00 \u03a9","C":"0.50 \u03a9","D":"0.05 \u03a9"},"answer":"A","explanation":"RL=2\u03c0fL=2\u03c0x100\u03c0x0.25=50.00\u03a9","marks":"1","difficulty":"3"},{"id":"objective>Physics>1995>42","subject":"Physics","year":"1995","type":"Objective","topic":"ELECTRIC FIELD : CURRENT ELECTRICITY","question":"If the current in the resistor R in Question 41 is 0.05 A, calculate the p.d across the inductor.","images":[],"options":{"A":"2.5 V","B":"25.0 V","C":"49.0 V","D":"50.0 V"},"answer":"A","explanation":"I = 0.05 A, p.d across RL = VL = IRL = 0.05 x 50  VL = 2.5 V","marks":"1","difficulty":"2"},{"id":"objective>Physics>1995>43","subject":"Physics","year":"1995","type":"Objective","topic":"ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION","question":"Acapacitorofcapacitance25\u03bcFisconnectedtoana.cpowersourceoffrequency200\u03c0Hz.  Calculatethereactanceofthecapacitor.","images":[],"options":{"A":"0.01 \u03a9","B":"0.02 \u03a9","C":"50.00 \u03a9","D":"100.00 \u03a9"},"answer":"D","explanation":"XC=12\u03c0fC=12\u03c0 x 200/\u03c0 x 25 x 10-6=12 x 200 x 25 x 10-6 = 110-2 = 102  \u2234XC=100.00\u03a9","marks":"1","difficulty":"3"},{"id":"objective>Physics>1995>44","subject":"Physics","year":"1995","type":"Objective","topic":"ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION","question":"The energy stored in a capacitor of capacitance 5\u03bcF is 40 J. Calculate the voltage applied across its terminal?","images":[],"options":{"A":"4000 V","B":"200 V","C":"16 V","D":"6 V"},"answer":"A","explanation":"E = 1/2QV; Q = CV  \u2234 E = 1/2CV2; 40 = 1/2 x 5 x 10-6 x V2    V2=2 x 40 x 1065  V2 = 16 x 106    \u2234 V = \u221a(16 x 106) = 4000 V","marks":"1","difficulty":"2"},{"id":"objective>Physics>1995>45","subject":"Physics","year":"1995","type":"Objective","topic":"ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION","question":"The effective capacitance between points X and Y in the diagram below is 1.0\u03bcF. What is the value of the capacitance C, measured in micro-farad.","images":["data:image/png;base64,"],"options":{"A":"5.0 \u03bc","B":"4.0 \u03bc","C":"3.0 \u03bc","D":"1.0 \u03bc"},"answer":"D","explanation":"Effective capacitance across the parallel = C + C = 2C  Effectivecapacitanceacrossthecircuit=12C+12=1 + C2C  \u2234Effectivecapacitanceacrossthecircuit=1 + C2C=11 or 2C1 + C = 11  1 + C = 2C; 2C - C = 1 \u2234 C = 1.0 \u03bc","marks":"1","difficulty":"2"},{"id":"objective>Physics>1995>46","subject":"Physics","year":"1995","type":"Objective","topic":"ELECTRIC FIELD : CURRENT ELECTRICITY","question":"Calculate the quantity of charge flowing through a conductor if a current of 10 A passes through the conductor for 10 s.","images":[],"options":{"A":"100 C","B":"20 C","C":"15 C","D":"10 C"},"answer":"A","explanation":"The quantity of charge flowing through a conductor is given by the formula Q = It. Substituting the given values, we get Q = 10*10 = 100 C.","marks":"1","difficulty":"1"},{"id":"objective>Physics>1995>47","subject":"Physics","year":"1995","type":"Objective","topic":"SIMPLE A.C. CIRCUITS : GRAPHICAL REPRESENTATION OF E.M.F AND CURRENT IN AN A.C. CIRCULT","question":"An alternating current, having a waveform shown in the diagram below, is represented by the equation X = Xosinwt. Which of the following represents Xo?","images":["data:image/png;base64,"],"options":{"A":"OS","B":"OR","C":"PQ","D":"RT"},"answer":"C","explanation":"Xo equals PQ because it is the amplitude or maximum current.","marks":"1","difficulty":"3"},{"id":"objective>Physics>1995>48","subject":"Physics","year":"1995","type":"Objective","topic":"ELECTRIC FIELD : POTENTIAL DIFFERENCE AND ELECTRIC CURRENT","question":"What is the potential difference between X and Y in the diagram below if the battery is of negligible internal resistance?","images":["data:image/png;base64,"],"options":{"A":"12.5 V","B":"5.8 V","C":"5.0 V","D":"3.0 V"},"answer":"D","explanation":"V=IR;1RXY=13+12=56\u2234 RXY=65\u03a9  \u2234RT=65+0.8=65+45=105=2\u03a9  V=IRT;5=2I;I=52A  \u2234VacrossXY= IRXY = 52x65=3.0V","marks":"1","difficulty":"2"},{"id":"objective>Physics>1995>49","subject":"Physics","year":"1995","type":"Objective","topic":"ELECTRIC FIELD : CURRENT ELECTRICITY","question":"Calculate the current in the 3 \u03a9 resistor in Question 48.","images":[],"options":{"A":"0.3 A","B":"0.4 A","C":"1.0 A","D":"1.5 A"},"answer":"C","explanation":"V = IR  Voltage across XY = 3 V = 3I  I=33=1.0A","marks":"1","difficulty":"2"},{"id":"objective>Physics>1995>50","subject":"Physics","year":"1995","type":"Objective","topic":"ELECTRIC FIELD : RESISTIVITY AND CONDUCTIVITY","question":"A given wire of resistance 10 \u03a9 has a length of 5 m and a cross-sectional area of 4.0 x 10-3 m2. Calculate the conductivity of the wire.","images":[],"options":{"A":"0.80 x 102 \u03a9-1m-1","B":"1.25 x 102 \u03a9-1m-1","C":"2.02 x 102 \u03a9-1m-1","D":"2.50 x 102 \u03a9-1m-1"},"answer":"B","explanation":"R=10\u03a9;L=5m;A=4.0x10-3m2  R=\u03c1LA  \u2234\u03c1=RAL=10 x 4.0 x 10-35=8.0x10-3\u03a9m  \u2234\u03c3=1\u03c1=18.0 x 10-3=1.25x102\u03a9-1m-1","marks":"1","difficulty":"2"},{"id":"objective>Physics>1995>51","subject":"Physics","year":"1995","type":"Objective","topic":"SOUND WAVES : SOURCES OF SOUND","question":"Which of the following is a wind instrument","images":[],"options":{"A":"Guitar","B":"Organ","C":"Violin","D":"Piano"},"answer":"B","explanation":"Organ is a keyboard instrument operated by the player's hands and feet, in which pressurized air produces notes through a series of pipes organized in a scalelike rows.","marks":"1","difficulty":"1"},{"id":"objective>Physics>1995>52","subject":"Physics","year":"1995","type":"Objective","topic":"ELECTRIC FIELD : CURRENT ELECTRICITY","question":"A cell of e.m.f 1.5 V and internal resistance 2.5 \u03a9 is connected in series with an ammeter of resistance 0.5 \u03a9 and a load of resistance 7.0 \u03a9. Calculate the current in the circuit.","images":[],"options":{"A":"0.15 A","B":"0.20 A","C":"2.10 A","D":"3.00 A"},"answer":"A","explanation":"E = 1.5 V; R = 7 + 0.5 = 7.5 \u03a9; r = 0.5 \u03a9  E = I(R + r)  I=E(R + r)=15(7.5 + 2.5)=1.510=0.15A","marks":"1","difficulty":"2"},{"id":"objective>Physics>1995>53","subject":"Physics","year":"1995","type":"Objective","topic":"ELECTRIC FIELD : ELECTRIC CIRCUIT","question":"Which of the following statements are not true of a moving-coil milliammeter?  I. It can be used to measure alternating current  II. It has a linear scale  III. It can be adapted to read higher values of currents  IV. A resistor connected in parallel with the milliameter would convert it to a voltmeter","images":[],"options":{"A":"I and IV only","B":"II and III only","C":"III and IV only","D":"I, II and III only"},"answer":"A","explanation":"It cannot measure alternating current (A.C) because of the rapidly changing direction of the current and it is a resistor (multiplier) connected in 'series' with it that can be used to convert it to a voltmeter.","marks":"1","difficulty":"3"},{"id":"objective>Physics>1995>54","subject":"Physics","year":"1995","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : RADIOACTIVITY","question":"A radioactive nuclide of mass 6.0 g has a half-life of 8 days. Calculate the time during which 5.25 g of the nuclide would have decayed","images":[],"options":{"A":"1 day","B":"2 days","C":"8 days","D":"24 days"},"answer":"D","explanation":"t1/2 = 8 days    Amount that decayed = 5.25 g    Amount that remains after time t = 6 - 5.25 = 0.75 g    i.e after 8 days, 6 g would decay to 3 g (remains half of its original amount)    After another 8 days it would remain 1.5 g    Finally, in another 8 days it would now remain 0.75 g    \u2234 After 3 half lives = 8 + 8 + 8 = 3 x 8 = 24 days      [OR]    t1/2 = 8 days    t1/2=0.693\u03bb  i.e8=0.693\u03bb==>\u03bb=0.6938=0.086625day-1  Initial amount (No) = 6.0 g    Amount that decayed = 5.25 g    Amount that remains after time t (N) = 6 - 5.25 = 0.75 g    N = No e -\u03bbt    0.75 = 6 e -0.086625t  =0.756= e -0.086625t  Take the natural log (ln) of both sides    =ln(0.756)=-0.086625t  = -2.079 = -0.086625t    \u2234t=-2.079-0.86625=24days","marks":"1","difficulty":"3"},{"id":"objective>Physics>1995>55","subject":"Physics","year":"1995","type":"Objective","topic":"ELECTRIC FIELD : SHUNT AND MULTIPLIER","question":"A moving-coil meter with an internal resistance of 100 \u03a9 has a full-scale deflection when a current of 10 mA flows through it. What value of resistance would convert it to read 10 V at full-scale deflection?","images":[],"options":{"A":"20 \u03a9","B":"100 \u03a9","C":"600 \u03a9","D":"900 \u03a9"},"answer":"D","explanation":"V=IR;V=10V;R=100\u03a9;I=101000=0.01A  Total voltage = Voltage across moving-coil meter + Voltage across resistor (Rm)    i.e 10 = 0.01 x 100 + 0.01Rm    = 10 = 1 + 0.01Rm    = 0.01Rm = 10 - 1 = 9    \u2234Rm=90.01=900\u03a9","marks":"1","difficulty":"2"},{"id":"objective>Physics>1995>56","subject":"Physics","year":"1995","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : RADIOACTIVITY","question":"Which of the following are emitted from a radioactive substance without altering either the nucleon number or the proton number of the substance?","images":[],"options":{"A":"Protons","B":"Neutrons","C":"Gamma rays","D":"Beta particles"},"answer":"C","explanation":"Gamma rays are emitted from a radioactive substance without altering either the nucleon number or the proton number of the substance. Gamma rays are a form of electromagnetic radiation, similar to X-rays and light, but with much higher energy. They are emitted during nuclear reactions, such as radioactive decay, but do not themselves carry any charge or mass, and therefore do not alter the nucleon or proton number of the emitting substance.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1995>57","subject":"Physics","year":"1995","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : FUSION AND FISSION","question":"Which of the following is not a result of nuclear fission?","images":[],"options":{"A":"Alpha particle","B":"Beta particle","C":"Gamma ray","D":"X-ray"},"answer":"D","explanation":"X-rays are not a result of nuclear fission although they can used to cause nuclear fission.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1995>58","subject":"Physics","year":"1995","type":"Objective","topic":"STRUCTURE OF THE ATOM : X-RAYS","question":"Calculate the energy carried by an X-ray of wavelength 6.0 x 10-10 m.   [Planck's constant = 6.6 x 10-34 Js, Velocity of light = 3 x 108 ms-1]","images":[],"options":{"A":"3.3 x 10-12 J","B":"3.3 x 10-16 J","C":"1.1 x 10-16 J","D":"3.3 x 10-24 J"},"answer":"B","explanation":"h = 6.6 x 10-34; c = 3 x 108 \u03bb = 6.0 x 10-10 m    E=hf=hc\u03bb=6.6 x 10-34 x 3 x 1086.0 x 10-10=3.3x10(-34 + 8 + 10)  \u2234 E = 3.3 x 10-16 J","marks":"1","difficulty":"3"},{"id":"objective>Physics>1995>59","subject":"Physics","year":"1995","type":"Objective","topic":"CONCEPTS OF MATTER : CONCEPTS OF MATTER","question":"Which of the following cannot be explained by the molecular theory of matter?","images":[],"options":{"A":"Conduction","B":"Radiation","C":"Convection","D":"Expansion"},"answer":"B","explanation":"The molecular theory of matter, also known as the kinetic theory of matter, explains the behavior of matter based on the idea that matter is made up of tiny particles that are always in motion. This theory can explain conduction, convection, and expansion, which are all processes that involve the movement of particles. However, it cannot explain radiation, which involves the emission of energy as electromagnetic waves.","marks":"1","difficulty":"2"},{"id":"objective>Physics>1995>60","subject":"Physics","year":"1995","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : RADIOACTIVITY","question":"Which of the following is used for shielding radioactive fall-outs?","images":[],"options":{"A":"Plastic","B":"Wood","C":"Textile","D":"Lead"},"answer":"D","explanation":"Lead is used because of its high density and large number of electrons, it is well suited to scattering x-rays and gamma-rays. When the radiation attempts to pass through lead, its electrons absorb and scatter the energy. Eventually though, the lead will degrade from the energy to which it is exposed.","marks":"1","difficulty":"3"}];